DROP TABLE IF EXISTS `conversation_state`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `conversation_state` (
  `id` int NOT NULL AUTO_INCREMENT,
  `conversation_id` varchar(64) NOT NULL,
  `user_id` int NOT NULL,
  `current_intent` varchar(50) DEFAULT NULL,
  `pending_intent` varchar(50) DEFAULT NULL,
  `required_slots` text,
  `filled_slots` text,
  `turn_count` int NOT NULL,
  `last_answer_type` varchar(30) DEFAULT NULL,
  `status` varchar(30) NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_conversation_user` (`conversation_id`,`user_id`),
  KEY `user_id` (`user_id`),
  KEY `ix_conversation_state_conversation_id` (`conversation_id`),
  CONSTRAINT `conversation_state_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=141 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
