INSERT INTO `guide_item` VALUES (1,1,'办公用品如何选购？','1. 登录公司 OA →「行政服务」→「办公用品申领」\n2. 选择常用耗材（笔、纸、文件夹等）并填写数量\n3. 部门负责人审批后，行政部每周二、四统一配送至工位\n4. 紧急需求可联系行政前台（内线 8001）说明用途\n\n提示：单价超过 200 元的物品需提前 1 个工作日申请。',0,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(2,1,'如何预约会议室？','在企业日历中搜索「会议室预订」，选择楼层与时段提交即可。\n超过 20 人的会议请提前 1 天预订，并注明是否需要投影/视频会议设备。',1,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(3,1,'电脑/网络问题找谁？','IT 服务台：内线 8090 或企业微信「IT 小助手」。\n常见问题（VPN、邮箱、打印机）可先查看 IT 知识库自助解决。',2,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(4,2,'如何请假？','1. OA →「考勤管理」→「请假申请」\n2. 选择假别（事假/病假/年假等），填写起止时间与事由\n3. 直属上级审批；3 天以上假期需部门负责人 + HR 备案\n\n病假超过 1 天需上传医院证明；年假需确保余额充足。',0,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(5,2,'年假有多少天？','按《休假与年假管理办法》：\n- 工龄 1–10 年：5 天/年\n- 工龄 10–20 年：10 天/年\n- 工龄 20 年以上：15 天/年\n\n具体天数可在 OA 考勤模块查看「年假余额」。',1,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(6,2,'迟到/忘打卡怎么办？','1. 忘记打卡：OA 提交「考勤异常说明」，选择日期与原因\n2. 或在智能问答「办事项」中发起考勤异常工单\n3. 每月补卡机会有限，频繁异常将影响绩效\n\n也可在智能问答中问「迟到怎么处理」了解制度规定。',2,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(7,3,'如何开具在职/收入证明？','智能问答 → 选择「办事项」→ 说明「我要开在职证明」。\n按提示填写用途、接收单位、是否需要盖章等信息，提交后 HR 会在 1–3 个工作日处理。',0,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(8,3,'手机号/邮箱变更怎么办理？','智能问答「办事项」→「个人信息变更」，填写原信息与新信息。\n也可携带有效证件到 HR 窗口办理，变更后请同步更新 OA 个人信息。',1,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(9,3,'报销流程是什么？','1. 费用发生后 30 天内，OA →「财务报销」上传发票与明细\n2. 选择费用类型（差旅/交通/餐饮等），关联项目或部门\n3. 审批通过后财务打款，一般 5–10 个工作日到账',2,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(10,4,'智能问答「查制度」能做什么？','用于查询公司制度：年假、请假、考勤、薪酬、绩效、入职转正等。\n示例：「年假有几天？」「婚假多少天？」「试用期多久？」',0,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(11,4,'智能问答「办事项」能做什么？','用于发起 HR 工单：在职证明、信息变更、考勤异常说明等。\n选择「办事项」模式后，用自然语言说明需求，系统会引导您补全信息。',1,'2026-07-05 13:47:47','2026-07-05 13:47:47'),(12,4,'在哪里看公司通知？','左侧菜单「通知公告」可查看全部、未读、置顶通知；重要政策变更会以置顶公告发布。',2,'2026-07-05 13:47:47','2026-07-05 13:47:47');
/*!40000 ALTER TABLE `guide_item` ENABLE KEYS */;
