--
-- Table structure for table `hr_document_version`
--

DROP TABLE IF EXISTS `hr_document_version`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `hr_document_version` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL,
  `version` varchar(20) NOT NULL,
  `file_path` varchar(500) DEFAULT NULL,
  `content_text` text,
  `created_by` int NOT NULL,
  `created_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `document_id` (`document_id`),
  KEY `created_by` (`created_by`),
  CONSTRAINT `hr_document_version_ibfk_1` FOREIGN KEY (`document_id`) REFERENCES `hr_document` (`id`),
  CONSTRAINT `hr_document_version_ibfk_2` FOREIGN KEY (`created_by`) REFERENCES `sys_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

