INSERT INTO `hr_document_version` VALUES (1,1,'1.0',NULL,'第一章 总则\n第一条 为规范公司考勤管理，维护正常工作秩序，根据国家相关法律法规，结合公司实际情况，制定本制度。\n第二条 本制度适用于公司全体员工。\n\n第二章 工作时间\n第三条 公司实行标准工时制，每周工作五天，休息两天。\n第四条 工作时间为上午9:00至12:00，下午13:30至18:00。\n第五条 因工作需要，经部门负责人批准，可安排弹性工作时间，但每天工作时间不少于8小时。\n\n第三章 打卡管理\n第六条 员工每日须通过公司考勤系统进行上下班打卡。\n第七条 忘记打卡的员工应在当日内通过系统提交补卡申请，经直属上级审批后生效。\n第八条 每月允许补卡次数不超过3次，超过3次需HR审批。\n第九条 未打卡且未补卡的视为旷工处理。\n\n第四章 迟到早退\n第十条 迟到或早退30分钟以内，每次扣减当月绩效分1分。\n第十一条 迟到或早退30分钟以上1小时以内，按旷工半天处理。\n第十二条 迟到或早退1小时以上，按旷工1天处理。\n第十三条 每月迟到早退累计3次及以上，将给予书面警告。\n\n第五章 加班管理\n第十四条 公司提倡高效工作，原则上不鼓励加班。\n第十五条 确因工作需要加班的，须提前通过系统提交加班申请，经部门负责人审批。\n第十六条 工作日加班可选择调休或按1.5倍计算加班费。\n第十七条 周末加班可选择调休或按2倍计算加班费。\n第十八条 法定节假日加班按3倍计算加班费。\n第十九条 调休须在加班后3个月内使用完毕，逾期自动作废。\n\n第六章 请假制度\n第二十条 员工请假须提前通过OA系统提交申请，审批流程如下：\n1天以内：直属上级审批\n1-3天：部门负责人审批\n3天以上：HR审批\n第二十一条 病假须提供医院证明，3天以上病假需提供二级以上医院证明。\n第二十二条 事假每月累计不超过3天，超过需HR审批。',1,'2026-06-30 14:24:03'),(2,2,'1.0',NULL,'第一章 总则\n第一条 为保障员工休假权利，规范休假管理，根据《职工带薪年休假条例》等法规，制定本办法。\n\n第二章 法定节假日\n第二条 员工依法享受国家规定的法定节假日，包括：\n元旦1天、春节3天、清明节1天、劳动节1天、端午节1天、中秋节1天、国庆节3天。\n\n第三章 带薪年假\n第三条 员工入职满一年后，享受带薪年假。年假天数按工龄计算：\n工龄1年以上不满10年：5天\n工龄10年以上不满20年：10天\n工龄20年以上：15天\n第四条 年假在一个年度内可以集中安排，也可以分段安排，一般不跨年度安排。\n第五条 公司因工作需要不能安排年假的，经员工本人同意，可以不安排年假，按照日工资的300%支付年假报酬。\n第六条 年假当年未使用完毕的，次年3月31日前可申请补休，逾期自动清零。\n第七条 新入职员工当年度年休假天数按照入职后剩余日历天数折算，折算后不足1天的不享受年假。\n\n第四章 婚假\n第八条 员工依法登记结婚，可享受婚假3天。\n第九条 婚假须在领证后6个月内使用完毕。\n\n第五章 产假\n第十条 女员工生育享受产假98天，其中产前可以休假15天。\n第十一条 难产的增加产假15天，多胞胎每多生育一个增加15天。\n第十二条 男员工享受陪产假15天。\n\n第六章 丧假\n第十三条 员工直系亲属去世，可享受丧假3天。\n第十四条 员工岳父母或公婆去世，可享受丧假1-3天。\n\n第七章 请假流程\n第十五条 请假须提前在OA系统提交申请，注明请假类型、起止时间及事由。\n第十六条 年假申请需提前3个工作日，其他假期需提前1个工作日。\n第十七条 紧急情况可先电话请假，事后补办手续。',1,'2026-06-30 14:24:03'),(3,3,'1.0',NULL,'第一章 总则\n第一条 为建立规范合理的薪酬体系，吸引和保留优秀人才，制定本制度。\n\n第二章 薪酬结构\n第二条 员工薪酬由基本工资、岗位工资、绩效工资和津贴补贴组成。\n第三条 基本工资根据岗位等级确定，岗位工资根据岗位职责和任职资格确定。\n第四条 绩效工资根据个人绩效考核结果发放，具体比例按照各岗位绩效方案执行。\n第五条 津贴补贴包括：交通补贴、通讯补贴、餐饮补贴等。\n\n第三章 薪资发放\n第六条 公司实行月薪制，每月15日发放上月工资，遇节假日提前发放。\n第七条 新入职员工薪资自报到之日起计算。\n第八条 员工薪资通过银行转账方式发放至个人账户。\n\n第四章 绩效奖金\n第九条 公司根据年度经营情况和个人绩效发放年终奖金。\n第十条 年终奖金一般于次年春节前发放。\n第十一条 年中离职的员工不享受当年度年终奖金。\n\n第五章 社会保险\n第十二条 公司按照国家规定为员工缴纳五险一金，包括：\n养老保险、医疗保险、失业保险、工伤保险、生育保险、住房公积金。\n第十三条 社保缴纳基数按照员工上年度月平均工资确定。\n\n第六章 补充福利\n第十四条 公司提供以下补充福利：\n1. 商业保险：公司为员工购买补充医疗保险和意外险；\n2. 节日福利：春节、端午、中秋等节日发放节日礼品或礼金；\n3. 生日福利：员工生日当月发放生日礼金200元；\n4. 健康体检：每年组织一次免费健康体检；\n5. 培训发展：提供各类培训和学习机会。\n\n第七章 报销制度\n第十五条 因公产生的费用可在规定标准内报销。\n第十六条 报销流程：\n1. 填写报销申请单，附上原始发票；\n2. 部门负责人审批（1000元以内）；\n3. 财务部审核；\n4. 总经理审批（5000元以上）；\n5. 财务部付款。\n第十七条 报销须在费用发生后30天内提交，逾期不予报销。',1,'2026-06-30 14:24:03'),(4,4,'1.0',NULL,'第一章 总则\n第一条 为建立科学的绩效管理体系，促进员工和公司共同发展，制定本制度。\n\n第二章 考核原则\n第二条 绩效考核坚持公平、公正、公开的原则。\n第三条 考核结果作为员工薪酬调整、晋升、培训的重要依据。\n\n第三章 考核周期\n第四条 绩效考核分为月度考核和年度考核。\n第五条 月度考核于次月5日前完成，年度考核于次年1月31日前完成。\n\n第四章 考核内容\n第六条 绩效考核内容包括：\n1. 工作业绩（60%）：完成工作任务的数量和质量；\n2. 工作能力（20%）：专业技能、沟通能力、学习能力等；\n3. 工作态度（20%）：责任心、主动性、团队合作等。\n\n第五章 考核流程\n第七条 绩效考核流程：\n1. 员工自评（权重20%）；\n2. 直属上级评价（权重50%）；\n3. 跨部门评价（权重30%）；\n4. HR汇总审核；\n5. 绩效面谈。\n\n第六章 考核等级\n第八条 绩效考核结果分为五个等级：\n优秀（A）：90分以上，占比不超过15%；\n良好（B）：80-89分，占比不超过30%；\n合格（C）：70-79分；\n待改进（D）：60-69分；\n不合格（E）：60分以下。\n\n第七章 绩效申诉\n第九条 员工对考核结果有异议的，可在结果公布后5个工作日内提出书面申诉。\n第十条 申诉流程：\n1. 向直属上级提出申诉；\n2. 如对处理结果不满，可向HR部门提出书面申诉；\n3. HR部门在收到申诉后10个工作日内完成调查并反馈结果；\n4. 申诉结果为最终决定。\n\n第八章 结果应用\n第十一条 绩效考核结果应用于：\n1. 绩效奖金发放；\n2. 薪资调整；\n3. 职位晋升；\n4. 培训需求分析；\n5. 劳动合同续签。',1,'2026-06-30 14:24:03'),(5,5,'1.0',NULL,'第一章 总则\n第一条 为规范员工入职和转正管理流程，帮助新员工快速融入公司，制定本办法。\n\n第二章 入职准备\n第二条 HR部门在员工入职前完成以下准备工作：\n1. 发送录用通知书，明确入职时间、地点、需携带材料；\n2. 准备办公设备、工位、门禁卡等；\n3. 开通邮箱、OA系统等账号；\n4. 通知用人部门做好接待准备。\n\n第三条 新员工入职当天需提交以下材料：\n1. 身份证原件及复印件；\n2. 学历证书原件及复印件；\n3. 离职证明；\n4. 近期一寸照片2张；\n5. 银行卡信息；\n6. 体检报告。\n\n第三章 入职流程\n第四条 入职当日流程：\n1. HR办理入职手续，签订劳动合同；\n2. 发放员工手册和入职指引；\n3. 介绍公司概况和企业文化；\n4. 引导至用人部门，介绍部门同事；\n5. 由导师带领熟悉工作环境。\n\n第四章 试用期管理\n第五条 试用期为3个月，自入职之日起计算。\n第六条 试用期工资为转正工资的80%。\n第七条 试用期内，员工需完成以下任务：\n1. 熟悉公司制度和业务流程；\n2. 完成部门安排的培训课程；\n3. 通过试用期考核。\n第八条 试用期考核内容：\n1. 专业技能（40%）；\n2. 工作态度（30%）；\n3. 学习能力（20%）；\n4. 团队融入（10%）。\n\n第五章 转正流程\n第九条 试用期满前15天，HR通知员工和用人部门启动转正评估。\n第十条 转正流程：\n1. 员工提交转正申请和试用期工作总结；\n2. 直属上级填写转正评估表；\n3. 部门负责人审批；\n4. HR部门审核；\n5. 总经理审批（主管级以上）。\n第十一条 转正审批通过后，HR更新系统信息，次月起按转正工资发放。\n第十二条 试用期考核不合格的，可延长试用期1个月或解除劳动合同。\n\n第六章 新员工培训\n第十三条 新员工入职培训包括：\n1. 公司概况和企业文化；\n2. 规章制度和行为规范；\n3. 业务流程和产品知识；\n4. 安全和保密教育。\n第十四条 部门培训由导师负责，为期1个月，包含岗位技能培训和实操练习。',1,'2026-06-30 14:24:03'),(6,6,'1.0','uploads\\20260702154901_休假与年假管理办法_测试样例.docx','休假与年假管理办法（测试样例）\n\n分类：休假    版本：V1.0    用途：FR-02-01 上传测试\n\n文档说明\n\n本文档为 HR Copilot 公司 HR 制度智能问答系统测试样例，用于验证 TXT / DOCX / PDF 制度文档上传、文件元信息保存、文本解析、关键词搜索和 RAG 来源引用能力。\n\n一、适用范围\n\n本办法适用于公司全体正式员工。试用期员工可根据劳动合同和公司规定享受相应假期。\n\n本文件用于 HR Copilot 制度上传、制度问答、来源引用和条件澄清测试。\n\n二、年假规则\n\n员工累计工作满 1 年不满 10 年的，每年享受 5 天年假。\n\n员工累计工作满 10 年不满 20 年的，每年享受 10 天年假。\n\n员工累计工作满 20 年及以上的，每年享受 15 天年假。\n\n员工询问“我今年有几天年假”时，如缺少工龄或入职日期，系统应先提示补充关键信息。\n\n三、请假申请流程\n\n员工申请年假、事假、病假等，应至少提前 1 个工作日提交请假申请。\n\n紧急情况无法提前申请的，应在返岗后 1 个工作日内补交说明。\n\n请假申请需经直属主管审批，必要时由 HR 备案。\n\n四、病假与事假\n\n员工申请病假时，应根据公司要求提交医疗证明或相关说明。\n\n员工申请事假时，应说明请假原因和预计返岗时间。\n\n五、假期余额与使用\n\n员工可在 HR 系统中查看个人年假余额。年假原则上应在当年度内使用。\n\n因业务原因无法按期休假的，员工可向 HR 咨询延期规则。\n\n六、制度解释\n\n本办法由人力资源部负责解释。若制度文件未覆盖员工问题，可通过 HR Copilot 提交人工请求。\n\n七、上传测试关键词表\n\n八、测试期望\n\n上传后系统应保存文件名、文件类型、分类、上传人、上传时间等元信息。\n\n系统应能解析正文内容，中文不乱码，内容不为空。\n\n后续关键词搜索和智能问答应能引用本文档中的相关条款。\n\n详细见附件',2,'2026-07-02 15:49:02'),(7,7,'1.0','uploads\\20260704153131_制度文档测试1.docx','员工在7月4日允许在18:00时下班',2,'2026-07-04 15:31:31'),(8,7,'1.0','uploads\\20260704153131_制度文档测试1.docx','员工在7月4日允许在18:00时下班',2,'2026-07-04 15:38:20'),(9,7,'1.1','uploads\\20260704153131_制度文档测试1.docx','员工在7月4日允许在17:00时下班',2,'2026-07-04 15:38:20'),(10,8,'1.0','uploads\\20260704164702_制度测试文档2.docx','员工允许在2026年7月5日17:30下班\n\n员工允许在2026年7月5日17:30下班',2,'2026-07-04 16:47:03'),(11,9,'1.0','uploads\\20260704170743_制度文档测试3.docx','7月6日员工需要加班到19:00下班\n\n7月6日员工需要加班到19:00下班',2,'2026-07-04 17:07:44');
