  `department_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `record_id` (`record_id`),
  KEY `user_id` (`user_id`),
  KEY `handler_id` (`handler_id`),
  CONSTRAINT `qa_feedback_ibfk_1` FOREIGN KEY (`record_id`) REFERENCES `qa_record` (`id`),
  CONSTRAINT `qa_feedback_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`),
  CONSTRAINT `qa_feedback_ibfk_3` FOREIGN KEY (`handler_id`) REFERENCES `sys_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
