INSERT INTO `qa_record` VALUES (1,3,'请假需要提前多久申请？','【FAQ回答】\n\n请假需提前通过OA系统提交申请：\n- 1天以内：直属上级审批\n- 1-3天：部门负责人审批\n- 3天以上：HR审批\n\n年假需提前3个工作日，其他假期需提前1个工作日。紧急情况可先电话请假，事后补办手续。','faq','[{\"faq_id\": 2, \"question\": \"\\u8bf7\\u5047\\u9700\\u8981\\u63d0\\u524d\\u591a\\u4e45\\u7533\\u8bf7\\uff1f\"}]',NULL,0,'6e31d001-1391-4e','2026-07-01 16:41:37'),(2,3,'报销流程是什么？','【FAQ回答】\n\n报销流程如下：\n1. 填写报销申请单，附上原始发票\n2. 部门负责人审批（1000元以内）\n3. 财务部审核\n4. 总经理审批（5000元以上）\n5. 财务部付款\n\n报销须在费用发生后30天内提交，逾期不予报销。','faq','[{\"faq_id\": 5, \"question\": \"\\u62a5\\u9500\\u6d41\\u7a0b\\u662f\\u4ec0\\u4e48\\uff1f\"}]',0,0,'449268cd-0b7d-43','2026-07-01 16:54:31'),(3,3,'年假怎么计算？','【FAQ回答】\n\n根据公司规定，年假按工龄计算：\n- 工龄1年以上不满10年：5天\n- 工龄10年以上不满20年：10天\n- 工龄20年以上：15天\n\n年假需提前3个工作日申请，当年未休完的年假次年3月31日前可补休，逾期自动清零。','faq','[{\"faq_id\": 1, \"question\": \"\\u5e74\\u5047\\u600e\\u4e48\\u8ba1\\u7b97\\uff1f\"}]',NULL,1,'71e67a79-3cda-42','2026-07-01 17:34:33'),(12,3,'想跑路了怎么办','您好！想帮您更好地解决问题，请问具体是哪种情况呢？\n\n1. **想离职**：需要了解辞职流程或交接注意事项？\n2. **想调整岗位**：希望内部转岗或申请休假？\n3. **遇到工作困扰**：比如人际关系、压力大或权益问题？\n\n请告诉我更多细节，我会尽力协助您~','clarification','[]',NULL,0,'5059af59-4382-45','2026-07-02 18:09:07'),(13,3,'算了, 我能发布一份公告吗?','根据现有知识库，未找到相关信息，无法回答关于员工发布公告的规定。提供的制度文档主要涵盖入职流程、绩效考核和考勤管理，未涉及公告发布权限或流程。','rag','[{\"doc_id\": 5, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u89c4\\u8303\\u5458\\u5de5\\u5165\\u804c\\u548c\\u8f6c\\u6b63\\u7ba1\\u7406\\u6d41\\u7a0b\\uff0c\\u5e2e\\u52a9\\u65b0\\u5458\\u5de5\\u5feb\\u901f\\u878d\\u5165\\u516c\\u53f8\\uff0c\\u5236\\u5b9a\\u672c\\u529e\\u6cd5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u5165\\u804c\\u51c6\\u5907\\n\\u7b2c\\u4e8c\\u6761 HR\\u90e8\\u95e8\\u5728\\u5458\\u5de5\\u5165\\u804c\\u524d\\u5b8c\\u6210\\u4ee5\\u4e0b\\u51c6\\u5907\\u5de5\\u4f5c\\uff1a\\n1. \\u53d1\\u9001\\u5f55\\u7528\\u901a\\u77e5\\u4e66\\uff0c\\u660e\\u786e\\u5165\\u804c\\u65f6\\u95f4\\u3001\\u5730\\u70b9\\u3001\", \"score\": 0.44}, {\"doc_id\": 4, \"chunk\": \"\\u7b2c\\u516d\\u7ae0 \\u8003\\u6838\\u7b49\\u7ea7\\n\\u7b2c\\u516b\\u6761 \\u7ee9\\u6548\\u8003\\u6838\\u7ed3\\u679c\\u5206\\u4e3a\\u4e94\\u4e2a\\u7b49\\u7ea7\\uff1a\\n\\u4f18\\u79c0\\uff08A\\uff09\\uff1a90\\u5206\\u4ee5\\u4e0a\\uff0c\\u5360\\u6bd4\\u4e0d\\u8d85\\u8fc715%\\uff1b\\n\\u826f\\u597d\\uff08B\\uff09\\uff1a80-89\\u5206\\uff0c\\u5360\\u6bd4\\u4e0d\\u8d85\\u8fc730%\\uff1b\\n\\u5408\\u683c\\uff08C\\uff09\\uff1a70-79\\u5206\\uff1b\\n\\u5f85\\u6539\\u8fdb\\uff08D\\uff09\\uff1a60-69\\u5206\\uff1b\", \"score\": 0.431}, {\"doc_id\": 1, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u89c4\\u8303\\u516c\\u53f8\\u8003\\u52e4\\u7ba1\\u7406\\uff0c\\u7ef4\\u62a4\\u6b63\\u5e38\\u5de5\\u4f5c\\u79e9\\u5e8f\\uff0c\\u6839\\u636e\\u56fd\\u5bb6\\u76f8\\u5173\\u6cd5\\u5f8b\\u6cd5\\u89c4\\uff0c\\u7ed3\\u5408\\u516c\\u53f8\\u5b9e\\u9645\\u60c5\\u51b5\\uff0c\\u5236\\u5b9a\\u672c\\u5236\\u5ea6\\u3002\\n\\u7b2c\\u4e8c\\u6761 \\u672c\\u5236\\u5ea6\\u9002\\u7528\\u4e8e\\u516c\\u53f8\\u5168\\u4f53\\u5458\\u5de5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u5de5\\u4f5c\\u65f6\\u95f4\\n\\u7b2c\\u4e09\\u6761 \\u516c\\u53f8\\u5b9e\\u884c\\u6807\\u51c6\\u5de5\\u65f6\\u5236\\uff0c\\u6bcf\", \"score\": 0.429}]',NULL,0,'5059af59-4382-45','2026-07-02 18:09:37'),(14,2,'我能发一份公告吗?','根据现有知识库，未找到相关信息，无法回答。提供的制度文档主要涉及员工入职、考勤和请假管理，未包含关于员工发布公告的内容。','rag','[{\"doc_id\": 5, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u89c4\\u8303\\u5458\\u5de5\\u5165\\u804c\\u548c\\u8f6c\\u6b63\\u7ba1\\u7406\\u6d41\\u7a0b\\uff0c\\u5e2e\\u52a9\\u65b0\\u5458\\u5de5\\u5feb\\u901f\\u878d\\u5165\\u516c\\u53f8\\uff0c\\u5236\\u5b9a\\u672c\\u529e\\u6cd5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u5165\\u804c\\u51c6\\u5907\\n\\u7b2c\\u4e8c\\u6761 HR\\u90e8\\u95e8\\u5728\\u5458\\u5de5\\u5165\\u804c\\u524d\\u5b8c\\u6210\\u4ee5\\u4e0b\\u51c6\\u5907\\u5de5\\u4f5c\\uff1a\\n1. \\u53d1\\u9001\\u5f55\\u7528\\u901a\\u77e5\\u4e66\\uff0c\\u660e\\u786e\\u5165\\u804c\\u65f6\\u95f4\\u3001\\u5730\\u70b9\\u3001\", \"score\": 0.445}