6210\\u90e8\\u95e8\\u5b89\\u6392\\u7684\\u57f9\\u8bad\", \"score\": 0.486}, {\"doc_id\": 4, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u5efa\\u7acb\\u79d1\\u5b66\\u7684\\u7ee9\\u6548\\u7ba1\\u7406\\u4f53\\u7cfb\\uff0c\\u4fc3\\u8fdb\\u5458\\u5de5\\u548c\\u516c\\u53f8\\u5171\\u540c\\u53d1\\u5c55\\uff0c\\u5236\\u5b9a\\u672c\\u5236\\u5ea6\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u8003\\u6838\\u539f\\u5219\\n\\u7b2c\\u4e8c\\u6761 \\u7ee9\\u6548\\u8003\\u6838\\u575a\\u6301\\u516c\\u5e73\\u3001\\u516c\\u6b63\\u3001\\u516c\\u5f00\\u7684\\u539f\\u5219\\u3002\\n\\u7b2c\\u4e09\\u6761 \\u8003\\u6838\\u7ed3\\u679c\\u4f5c\\u4e3a\\u5458\\u5de5\\u85aa\\u916c\\u8c03\\u6574\\u3001\\u664b\\u5347\\u3001\\u57f9\\u8bad\\u7684\\u91cd\", \"score\": 0.46}]',NULL,0,'8fe0fd9c-436f-4f','2026-07-03 09:22:43'),(147,3,'年假怎么休？','根据制度文档，年假的休法如下：\n\n1. **资格**：员工入职满一年后享受带薪年假。\n2. **天数**：按工龄计算：1-10年5天，10-20年10年，20年以上15天。\n3. **安排**：年假可在年度内集中或分段安排，一般不跨年度。\n4. **申请**：需提前3个工作日在OA系统提交请假申请。\n5. **特殊情况**：公司因工作需要不能安排年假时，经员工同意可不安排','rag','[{\"doc_id\": 2, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u4fdd\\u969c\\u5458\\u5de5\\u4f11\\u5047\\u6743\\u5229\\uff0c\\u89c4\\u8303\\u4f11\\u5047\\u7ba1\\u7406\\uff0c\\u6839\\u636e\\u300a\\u804c\\u5de5\\u5e26\\u85aa\\u5e74\\u4f11\\u5047\\u6761\\u4f8b\\u300b\\u7b49\\u6cd5\\u89c4\\uff0c\\u5236\\u5b9a\\u672c\\u529e\\u6cd5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u6cd5\\u5b9a\\u8282\\u5047\\u65e5\\n\\u7b2c\\u4e8c\\u6761 \\u5458\\u5de5\\u4f9d\\u6cd5\\u4eab\\u53d7\\u56fd\\u5bb6\\u89c4\\u5b9a\\u7684\\u6cd5\\u5b9a\\u8282\\u5047\\u65e5\\uff0c\\u5305\\u62ec\\uff1a\\n\\u5143\\u65e61\\u5929\\u3001\\u6625\\u82823\\u5929\\u3001\\u6e05\\u660e\", \"score\": 0.619}, {\"doc_id\": 2, \"chunk\": \"\\u7b2c\\u56db\\u7ae0 \\u5a5a\\u5047\\n\\u7b2c\\u516b\\u6761 \\u5458\\u5de5\\u4f9d\\u6cd5\\u767b\\u8bb0\\u7ed3\\u5a5a\\uff0c\\u53ef\\u4eab\\u53d7\\u5a5a\\u50473\\u5929\\u3002\\n\\u7b2c\\u4e5d\\u6761 \\u5a5a\\u5047\\u987b\\u5728\