3\\u5229\\uff0c\\u89c4\\u8303\\u4f11\\u5047\\u7ba1\\u7406\\uff0c\\u6839\\u636e\\u300a\\u804c\\u5de5\\u5e26\\u85aa\\u5e74\\u4f11\\u5047\\u6761\\u4f8b\\u300b\\u7b49\\u6cd5\\u89c4\\uff0c\\u5236\\u5b9a\\u672c\\u529e\\u6cd5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u6cd5\\u5b9a\\u8282\\u5047\\u65e5\\n\\u7b2c\\u4e8c\\u6761 \\u5458\\u5de5\\u4f9d\\u6cd5\\u4eab\\u53d7\\u56fd\\u5bb6\\u89c4\\u5b9a\\u7684\\u6cd5\\u5b9a\\u8282\\u5047\\u65e5\\uff0c\\u5305\\u62ec\\uff1a\\n\\u5143\\u65e61\\u5929\\u3001\\u6625\\u82823\\u5929\\u3001\\u6e05\\u660e\", \"score\": 0.402}, {\"doc_id\": 1, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u89c4\\u8303\\u516c\\u53f8\\u8003\\u52e4\\u7ba1\\u7406\\uff0c\\u7ef4\\u62a4\\u6b63\\u5e38\\u5de5\\u4f5c\\u79e9\\u5e8f\\uff0c\\u6839\\u636e\\u56fd\\u5bb6\\u76f8\\u5173\\u6cd5\\u5f8b\\u6cd5\\u89c4\\uff0c\\u7ed3\\u5408\\u516c\\u53f8\\u5b9e\\u9645\\u60c5\\u51b5\\uff0c\\u5236\\u5b9a\\u672c\\u5236\\u5ea6\\u3002\\n\\u7b2c\\u4e8c\\u6761 \\u672c\\u5236\\u5ea6\\u9002\\u7528\\u4e8e\\u516c\\u53f8\\u5168\\u4f53\\u5458\\u5de5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u5de5\\u4f5c\\u65f6\\u95f4\\n\\u7b2c\\u4e09\\u6761 \\u516c\\u53f8\\u5b9e\\u884c\\u6807\\u51c6\\u5de5\\u65f6\\u5236\\uff0c\\u6bcf\", \"score\": 0.392}]',NULL,0,'cd35f643-6191-4a','2026-07-03 09:24:28'),(163,3,'那迟到呢？','你这个问题需要结合上下文才能准确回答。\n\n请补充你想了解的具体内容，例如：\n1. 年假天数或工龄福利\n2. 考勤、迟到、补卡相关规定\n3. 请假、试用期或其他制度','clarification','[]',NULL,0,'cfe33ced-72e3-4c','2026-07-03 09:47:41'),(164,3,'这个需要提交说明吗？','我注意到您的问题可能需要补充一些信息。\n\n**问题分析：** 存在指代不明\n\n**建议：** 请具体说明您指的是什么\n\n例如：您可以问「试用期多久？」或「报销流程是什么？」','clarification','[]',NULL,0,'cfe33ced-72e3-4c','2026-07-03 09:48:39'),(165,3,'那迟到呢？','根据制度文档，迟到处理如下：\n\n- 迟到30分钟以内：每次扣减当月绩效分1分。\n- 迟到30分钟以上1小时以内：按旷工半天处理。\n- 迟到1小时以上：按旷工1天处理。\n- 每月迟到早退累计3次及以上：给予书面警告。','rag','[{\"doc_id\": 1, \"chunk\": \"\\u7b2c\\u56db\\u7ae0 \\u8fdf\\u5230\\u65e9\\u9000\\n\\u7b2c\\u5341\\u6761 \\u8fdf\\u5230\\u6216\\u65e9\\u900030\\u5206\\u949f\\u4ee5\\u5185\\uff0c\\u6bcf\\u6b21\\u6263\\u51cf\\u5f53\\u6708\\u7ee9\\u6548\\u52061\\u5206\\u3002\\n\\u7b2c\\u5341\\u4e00\\u6761 \\u8fdf\\u5230\\u6216\\u65e9\\u900030\\u5206\\u949f\\u4ee5\\u4e0a1\\u5c0f\\u65f6\\u4ee5\\u5185\\uff0c\\u6309\\u65f7\\u5de5\\u534a\\u5929\\u5904\\u7406\\u3002\\n\\u7b2c\\u5341\\u4e8c\\u6761 \\u8fdf\\u5230\\u6216\\u65e9\\u90001\\u5c0f\\u65f6\\u4ee5\\u4e0a\\uff0c\\u6309\\u65f7\\u5de51\\u5929\\u5904\\u7406\\u3002\\n\\u7b2c\\u5341\\u4e09\\u6761 \\u6bcf\", \"score\": 0.549}, {\"doc_id\": 4, \"chunk\": \"\\u7b2c\\u516d\\u7ae0 \\u8003\\u6838\\u7b49\\u7ea7\\n\\u7b2c\\u516b\\u6761 \\u7ee9\\u6548\\u8003\\u6838\\u7ed3\\u679c\\u5206\\u4e3a\\u4e94\\u4e2a\\u7b49\\u7ea7\\uff1a\\n\\u4f18\\u79c0\\uff08A\\uff09\\uff1a90\\u5206\\u4ee5\\u4e0a\\uff0c\\u5360\\u6bd4\\u4e0d\\u8d85\\u8fc715%\\uff1b\\n\\u826f\\u597d\\uff08B\\uff09\\uff1a80-89\\u5206\\uff0c\\u5360\\u6bd4\\u4e0d\\u8d85\\u8fc730%\\uff1b\\n\\u5408\\u683c\\uff08C\\uff09\\uff1a70-79\\u5206\\uff1b\\n\\u5f85\\u6539\\u8fdb\\uff08D\\uff09\\uff1a60-69\\u5206\\uff1b\", \"score\": 0.419}, {\"doc_id\": 1, \"chunk\": \"\\u7b2c\\u516d\\u7ae0 \\u8bf7\\u5047\\u5236\\u5ea6\\n\\u7b2c\\u4e8c\\u5341\\u6761 \\u5458\\u5de5\\u8bf7\\u5047\\u987b\\u63d0\\u524d\\u901a\\u8fc7OA\\u7cfb\\u7edf\\u63d0\\u4ea4\\u7533\\u8bf7\\uff0c\\u5ba1\\u6279\\u6d41\\u7a0b\\u5982\\u4e0b\\uff1a\\n1\\u5929\\u4ee5\\u5185\\uff1a\\u76f4\\u5c5e\\u4e0a\\u7ea7\\u5ba1\\u6279\\n1-3\\u5929\\uff1a\\u90e8\\u95e8\\u8d1f\\u8d23\\u4eba\\u5ba1\\u6279\\n3\\u5929\\u4ee5\\u4e0a\\uff1aHR\\u5ba1\\u6279\\n\\u7b2c\\u4e8c\\u5341\\u4e00\\u6761 \\u75c5\\u5047\\u987b\\u63d0\\u4f9b\\u533b\\u9662\\u8bc1\\u660e\\uff0c3\\u5929\\u4ee5\\u4e0a\\u75c5\\u5047\\u9700\\u63d0\\u4f9b\", \"score\": 0.404}]',NULL,0,'07534a3a-96fc-4a','2026-07-03 09:52:37'),(166,3,'这个需要提交说明吗？','结合您之前关于考勤的问题，关于迟到/早退是否需要提交说明：\n\n根据公司《考勤管理制度》：\n- **30分钟以内**：扣减当月绩效分1分，一般无需另行提交书面说明\n- **超过30分钟**：按旷工处理，建议当日通过考勤系统提交考勤异常说明，经直属上级审批\n- **忘记打卡/漏打卡**：需在当日内提交补卡申请\n\n如有特殊情况或需 HR 协助，可以说「我想提交考勤异常说明」创建工单。','rule','[{\"source\": \"\\u8003\\u52e4\\u5236\\u5ea6\", \"document\": \"\\u8003\\u52e4\\u7ba1\\u7406\\u5236\\u5ea6\", \"name\": \"\\u8fdf\\u5230\\u65e9\\u9000\\u89c4\\u5219\"}]',NULL,0,'07534a3a-96fc-4a','2026-07-03 09:52:46'),(167,3,'公司年假是按什么标准算的？','根据制度文档，公司年假是按员工累计工龄计算的，具体标准如下：\n\n*   **工龄满1年不满10年**：年假 **5天**\n*   **工龄满10年不满20年**：年假 **10天**\n*   **工龄满20年以上**：年假 **15天**\n\n员工入职满一年后开始享受带薪年假。','rag','[{\"doc_id\": 2, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u4fdd\\u969c\\u5458\\u5de5\\u4f11\\u5047\\u6743\\u5229\\uff0c\\u89c4\\u8303\\u4f11\\u5047\\u7ba1\\u7406\\uff0c\\u6839\\u636e\\u300a\\u804c\\u5de5\\u5e26\\u85aa\\u5e74\\u4f11\\u5047\\u6761\\u4f8b\\u300b\\u7b49\\u6cd5\\u89c4\\uff0c\\u5236\\u5b9a\\u672c\\u529e\\u6cd5\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u6cd5\\u5b9a\\u8282\\u5047\\u65e5\\n\\u7b2c\\u4e8c\\u6761 \\u5458\\u5de5\\u4f9d\\u6cd5\\u4eab\\u53d7\\u56fd\\u5bb6\\u89c4\\u5b9a\\u7684\\u6cd5\\u5b9a\\u8282\\u5047\\u65e5\\uff0c\\u5305\\u62ec\\uff1a\\n\\u5143\\u65e61\\u5929\\u3001\\u6625\\u82823\\u5929\\u3001\\u6e05\\u660e\", \"score\": 0.704}, {\"doc_id\": 3, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u5efa\\u7acb\\u89c4\\u8303\\u5408\\u7406\\u7684\\u85aa\\u916c\\u4f53\\u7cfb\\uff0c\\u5438\\u5f15\\u548c\\u4fdd\\u7559\\u4f18\\u79c0\\u4eba\\u624d\\uff0c\\u5236\\u5b9a\\u672c\\u5236\\u5ea6\\u3002\\n\\n\\u7b2c\\u4e8c\\u7ae0 \\u85aa\\u916c\\u7ed3\\u6784\\n\\u7b2c\\u4e8c\\u6761 \\u5458\\u5de5\\u85aa\\u916c\\u7531\\u57fa\\u672c\\u5de5\\u8d44\\u3001\\u5c97\\u4f4d\\u5de5\\u8d44\\u3001\\u7ee9\\u6548\\u5de5\\u8d44\\u548c\\u6d25\\u8d34\\u8865\\u8d34\\u7ec4\\u6210\\u3002\\n\\u7b2c\\u4e09\\u6761 \\u57fa\\u672c\\u5de5\\u8d44\\u6839\\u636e\\u5c97\\u4f4d\\u7b49\\u7ea7\\u786e\\u5b9a\\uff0c\", \"score\": 0.573}, {\"doc_id\": 1, \"chunk\": \"\\u7b2c\\u4e00\\u7ae0 \\u603b\\u5219\\n\\u7b2c\\u4e00\\u6761 \\u4e3a\\u89c4\\u8303\\u516c\\u53f8\\u8003\\u52e4\\u7ba1\\u7406\\uff0c\\u7ef4\\u62a4\\u6b63\\u5e38\\u5de5\\u4f5c\\u79e9\\u5e8f\\uff0c\\u6839\\u636e\\u56fd\\u5bb6\\u76f