INSERT INTO `qa_rule` VALUES (1,'HR联系方式查询','客服电话,HR电话,联系HR,HR联系方式','HR部门联系方式：\n- 电话：010-88888888\n- 邮箱：hr@company.com\n- 办公地点：总部大楼3层人力资源部\n- 工作时间：周一至周五 9:00-18:00\n\n如有紧急事务，可拨打HR直线：13800138000','contact',10,1,2,'2026-06-30 14:24:03','2026-06-30 14:24:03',NULL),(2,'工作时间查询','上班时间,工作时间,上下班,几点上班','公司工作时间：\n- 上午：9:00 - 12:00\n- 午休：12:00 - 13:30\n- 下午：13:30 - 18:00\n- 周六日休息\n\n实行标准工时制，每天工作8小时。','attendance',9,1,2,'2026-06-30 14:24:03','2026-06-30 14:24:03',NULL),(3,'补卡规则','打卡,忘记打卡,补卡,漏打卡','忘记打卡补卡规则：\n1. 当日内通过考勤系统提交补卡申请\n2. 经直属上级审批后生效\n3. 每月允许补卡次数不超过3次\n4. 超过3次需HR审批\n5. 未打卡且未补卡的视为旷工\n\n请养成按时打卡的好习惯！','attendance',8,1,2,'2026-06-30 14:24:03','2026-06-30 14:24:03',NULL);
/*!40000 ALTER TABLE `qa_rule` ENABLE KEYS */;
