INSERT INTO `sys_notice` VALUES (1,'2026年端午节放假通知','根据国家规定，2026年端午节放假安排如下：\n\n放假时间：6月19日（星期五）至6月21日（星期日），共3天。\n6月22日（星期一）正常上班。\n\n请各部门提前做好工作安排，确保假期期间值班人员到位。\n\n祝大家端午节快乐！','holiday',1,2,NULL,'2026-06-30 14:24:03',NULL),(2,'年假清零提醒','各位同事：\n\n根据公司《休假与年假管理办法》规定，上年度未使用完毕的年假将于2026年3月31日自动清零。\n\n请各位同事合理安排时间，在截止日期前使用剩余年假。\n\n如有疑问，请联系HR部门。','reminder',0,2,'2026-03-31 00:00:00','2026-06-30 14:24:03',NULL),(3,'新版考勤制度发布通知','各位同事：\n\n为规范公司考勤管理，公司修订了《考勤管理制度》（2026年版），现予以发布。\n\n主要变化：\n1. 弹性工作时间调整为每月可申请3次\n2. 补卡次数调整为每月不超过3次\n3. 新增远程办公相关规定\n\n新制度自2026年7月1日起执行，请各部门组织学习。\n\n制度全文请查看制度文档库。','policy',1,2,NULL,'2026-06-30 14:24:03',NULL),(4,'关于2024年年假清零的通知','各位员工：根据公司规定，2024年年假将于12月31日清零，请及时使用。','general',1,2,NULL,'2026-07-01 16:37:05',NULL),(5,'中秋节放假安排','中秋节放假3天：9月15日至17日，9月14日（周六）正常上班。','general',0,2,NULL,'2026-07-01 16:37:05',NULL),(6,'员工体检通知','年度员工体检将于10月8日-10月12日在市第一医院进行，请各部门安排好时间。','general',0,2,NULL,'2026-07-01 16:37:05',NULL),(7,'这是一次公告测试!','请输入文本','general',0,2,NULL,'2026-07-01 16:58:09',NULL),(8,'公告测试2','这是一次基础公告测试2','general',0,2,NULL,'2026-07-02 16:10:45',NULL),(9,'公告测试3','123','general',0,2,NULL,'2026-07-02 16:40:35',NULL),(10,'休假','周五休假一天','holiday',0,2,NULL,'2026-07-02 18:22:40',NULL),(11,'7月4日下班提前','7月4日放假提前至17:00','holiday',0,2,NULL,'2026-07-04 16:53:38',NULL),(12,'开会提醒','7月4日下班前需要开一次组会','reminder',0,2,NULL,'2026-07-04 17:16:06',NULL),(13,'关于2026年年假安排的通知','各位同事:\n\n根据公司规定,2026年年假安排如下:\n1. 年假有效期为2026年1月1日至2026年12月31日\n2. 请各部门合理安排员工休假计划\n3. 年假需提前3天申请\n\n特此通知.','general',1,5,'2026-08-02 14:07:30','2026-06-25 14:07:30',NULL),(14,'公司团建活动通知','各位同事:\n\n为增进同事间的交流与合作,公司定于7月20日组织团建活动.\n活动地点:XX拓展基地\n集合时间:早上8:30\n请各位同事准时参加.','activity',0,21,'2026-07-25 14:07:30','2026-07-05 14:07:30',NULL),(15,'关于规范考勤管理的通知','各位同事:\n\n为加强公司考勤管理,现将有关事项通知如下:\n1. 工作时间为上午9:00-12:00,下午13:30-18:00\n2. 迟到30分钟以内需说明原因\n3. 请务必按时打卡\n\n特此通知.','policy',1,16,'2026-08-01 14:07:30','2026-06-29 14:07:30',NULL),(16,'系统维护通知','各位同事:\n\n公司OA系统将于本周六(7月11日)22:00至次日6:00进行维护升级,届时系统将暂停服务.\n请各位同事提前做好相关工作安排.\n\n给您带来不便,敬请谅解.','system',0,25,'2026-07-20 14:07:30','2026-07-04 14:07:30',NULL),(17,'关于端午节放假安排的通知','各位同事:\n\n根据国家法定节假日安排,端午节放假时间为6月25日至6月27日,共3天.\n6月28日(周日)正常上班.\n请各部门做好工作安排.\n\n祝大家端午节快乐!','holiday',1,16,'2026-07-30 14:07:30','2026-07-04 14:07:30',NULL);
